// Compute x/y for pins that only have lat/lng
samplePins.forEach(pin => {
  if (pin.lat != null && pin.lng != null && pin.x === 0 && pin.y === 0) {
    const coords = latLngToXY(pin.lat, pin.lng);
    pin.x = coords.x;
    pin.y = coords.y;
  }
});

